import{_ as o,o as t,c as r,a5 as c}from"./chunks/framework.B5tqjWbr.js";const u=JSON.parse('{"title":"教程 0006：Boost C 固件骨架","description":"","frontmatter":{"title":"教程 0006：Boost C 固件骨架","date":"2026-07-02T00:00:00.000Z","section":"电源控制","chapter":"01-Lessons","chapterTitle":"电源课程","category":"电源控制","tags":["imported"],"source":"power","sourcePath":"0006-boost-c-firmware-skeleton.html","status":"learning","visibility":"public","summary":"Imported from 0006-boost-c-firmware-skeleton.html","chapterOrder":10},"headers":[],"relativePath":"content/power/lessons/0006-boost-c-firmware-skeleton.md","filePath":"content/power/lessons/0006-boost-c-firmware-skeleton.md","lastUpdated":null}'),a={name:"content/power/lessons/0006-boost-c-firmware-skeleton.md"};function l(i,e,p,n,d,s){return t(),r("div",null,[...e[0]||(e[0]=[c(`<h1 id="教程-0006-boost-c-固件骨架" tabindex="-1">教程 0006：Boost C 固件骨架 <a class="header-anchor" href="#教程-0006-boost-c-固件骨架" aria-label="Permalink to &quot;教程 0006：Boost C 固件骨架&quot;">​</a></h1><p>中文主讲。一个概念：把 Boost 控制中断软件骨架拆成可阅读、可编译的简化 C 工程。</p><pre><code>目录
</code></pre><ul><li><p>它是什么</p></li><li><p>为什么 UPS 需要它</p></li><li><p>物理直觉</p></li><li><p>数学形式</p></li><li><p>一个仿真任务与仿真观察</p></li><li><p>固件落地</p></li><li><p>常见误解</p></li><li><p>验收标准、复盘问题、导师问题</p></li></ul><p>**保密边界：**本节只使用教学代码，不包含公司内部代码、未公开产品方案、客户项目参数或内部测试数据。</p><h2 id="_1-它是什么" tabindex="-1">1. 它是什么 <a class="header-anchor" href="#_1-它是什么" aria-label="Permalink to &quot;1. 它是什么&quot;">​</a></h2><p>Boost C 固件骨架（Boost C firmware skeleton）是一个可编译的小型 C 工程，用来表达前一节 控制中断服务程序（control interrupt service routine / control ISR）的数据流。</p><p>ADC 采样 -&gt; 保护判断 -&gt; 控制 ISR -&gt; PWM 输出 -&gt; 状态机锁存</p><p>这里的 模数转换器（analog-to-digital converter / ADC） 不连接真实硬件，只返回一组教学采样值。脉宽调制（pulse-width modulation / PWM） 也不驱动开关管，只保存并打印占空比命令。</p><h2 id="_2-为什么-ups-需要它" tabindex="-1">2. 为什么 UPS 需要它 <a class="header-anchor" href="#_2-为什么-ups-需要它" aria-label="Permalink to &quot;2. 为什么 UPS 需要它&quot;">​</a></h2><p>不间断电源（uninterruptible power supply / UPS）软件需要同时处理控制、保护、状态和硬件接口。你入职后读到的 C 工程很可能不是一个长函数，而是一组互相调用的模块。</p><pre><code>采样边界
</code></pre><p>adc.c 提供电压、电流采样。 保护边界 protection.c 判断过压、欠压、过流。 控制边界 control.c 计算占空比并决定是否关断。 输出边界 pwm.c 接收占空比或执行强制关断。</p><h2 id="_3-物理直觉" tabindex="-1">3. 物理直觉 <a class="header-anchor" href="#_3-物理直觉" aria-label="Permalink to &quot;3. 物理直觉&quot;">​</a></h2><p>C 工程里的模块边界，本质上是在给能量流加安全门。采样值先经过保护门，只有确认安全，比例积分控制器（proportional-integral controller / PI）才允许计算新的占空比。只要检测到过压，软件立刻进入故障状态并关断 PWM。</p><pre><code>adc.c
AdcSample

protection.c
Fault check

control.c
Boost_ControlIsr

pwm.c
Duty / Off

state_machine.c
RUN / FAULT

fault -&gt; PWM off
</code></pre><p>图 1：教学 C 骨架的模块边界。真实工程会增加硬件抽象层（hardware abstraction layer / HAL）、通信、日志和参数管理。</p><h2 id="_4-数学形式" tabindex="-1">4. 数学形式 <a class="header-anchor" href="#_4-数学形式" aria-label="Permalink to &quot;4. 数学形式&quot;">​</a></h2><p>本节仍然只讲一个概念：保护优先的控制 ISR。核心伪代码如下：</p><p>fault = Protection_Check(sample, config) if fault != NONE: runtime.fault = fault runtime.state = FAULT Pwm_ForceOff() else: error = Vref - Vout integrator = clamp(integrator + Ki * error * Ts) duty = clamp(Kp * error + integrator) Pwm_SetDuty(duty)</p><p>数学上，PI 只是后半段：<code>D[k] = clamp(Kp * e[k] + I[k])</code>。工程上，保护判断和状态锁存决定这条公式有没有资格执行。</p><h2 id="_5-一个仿真任务与仿真观察" tabindex="-1">5. 一个仿真任务与仿真观察 <a class="header-anchor" href="#_5-一个仿真任务与仿真观察" aria-label="Permalink to &quot;5. 一个仿真任务与仿真观察&quot;">​</a></h2><p>这里的一个仿真任务是编译并运行一个 C 教学程序。它不会生成图片，因为本节重点是代码结构和状态输出；前面五节的 Python 仿真仍用于观察波形。</p><p>cd E:\\gitee_CodeStorage\\学习\\电源 gcc -std=c99 -Wall -Wextra -Werror -I projects\\02-boost-c-firmware-skeleton\\src projects\\02-boost-c-firmware-skeleton\\src*.c -o projects\\02-boost-c-firmware-skeleton\\boost_c_firmware_skeleton.exe projects\\02-boost-c-firmware-skeleton\\boost_c_firmware_skeleton.exe</p><pre><code>观察点
</code></pre><ul><li><p><code>tick=00</code> 到 <code>tick=02</code>：状态应为 <code>RUN</code>，故障为 <code>NONE</code>，PWM 非零。</p></li><li><p><code>tick=03</code>：教学 ADC 采样给出 <code>vout=132.0</code>，超过过压阈值，进入 <code>FAULT</code>。</p></li><li><p><code>tick=04</code>：即使采样恢复到 <code>vout=90.0</code>，故障仍锁存，<code>pwm=0.000</code>。</p></li></ul><h2 id="_6-固件落地" tabindex="-1">6. 固件落地 <a class="header-anchor" href="#_6-固件落地" aria-label="Permalink to &quot;6. 固件落地&quot;">​</a></h2><p>阅读真实 C 工程时，可以沿着这些入口找：</p><ul><li><p><code>boost_types.h</code>：先看采样、配置、运行状态和故障码结构。</p></li><li><p><code>control.c -&gt; Boost_ControlIsr()</code>：看控制 ISR 顺序。</p></li><li><p><code>protection.c -&gt; Protection_Check()</code>：看保护阈值和故障码。</p></li><li><p><code>pwm.c -&gt; Pwm_SetDuty()/Pwm_ForceOff()</code>：看正常输出和安全关断接口。</p></li><li><p><code>state_machine.c -&gt; StateMachine_Step()</code>：看状态如何进入故障。</p></li></ul><h2 id="_7-常见误解" tabindex="-1">7. 常见误解 <a class="header-anchor" href="#_7-常见误解" aria-label="Permalink to &quot;7. 常见误解&quot;">​</a></h2><ul><li><p>**误解：**C 工程只是 Python 控制函数翻译。 **纠正：**C 工程更重视模块边界、状态保存、实时调度和硬件接口。</p></li><li><p>**误解：**保护可以放在 PI 后面。 **纠正：**危险采样应先触发关断，不能先计算新的 PWM 命令。</p></li><li><p>**误解：**故障后采样恢复就应自动运行。 **纠正：**严重故障通常锁存，复位需要状态机条件。</p></li></ul><h2 id="_8-验收标准" tabindex="-1">8. 验收标准 <a class="header-anchor" href="#_8-验收标准" aria-label="Permalink to &quot;8. 验收标准&quot;">​</a></h2><ul><li><p>能解释 <code>Boost_ControlIsr()</code> 的输入、状态、配置和输出。</p></li><li><p>能说出为什么保护判断在控制计算之前。</p></li><li><p>能根据终端输出指出过压发生在哪个 tick。</p></li><li><p>能解释为什么 <code>tick=04</code> 仍然是 <code>FAULT</code>。</p></li><li><p>能用 <code>control.c</code> 和 <code>pwm.c</code> 准备具体导师问题。</p></li></ul><h2 id="_9-复盘问题" tabindex="-1">9. 复盘问题 <a class="header-anchor" href="#_9-复盘问题" aria-label="Permalink to &quot;9. 复盘问题&quot;">​</a></h2><ul><li><p><code>tick=03</code> 的 <code>vout</code> 是多少？为什么触发过压？</p></li><li><p>如果把 <code>Protection_Check()</code> 放到 PI 计算之后，最坏会发生什么？</p></li><li><p><code>Pwm_SetDuty()</code> 和 <code>Pwm_ForceOff()</code> 为什么应该分成两个接口？</p></li></ul><h2 id="_10-导师问题" tabindex="-1">10. 导师问题 <a class="header-anchor" href="#_10-导师问题" aria-label="Permalink to &quot;10. 导师问题&quot;">​</a></h2><ul><li><p>我用 <code>projects/02-boost-c-firmware-skeleton/src/control.c</code> 看到 <code>Boost_ControlIsr()</code> 先执行保护再更新 PWM。公司工程里控制 ISR 的顺序是否类似？</p></li><li><p>我看到 <code>pwm.c</code> 中教学代码把正常占空比输出和强制关断分开。真实工程里软件关断和硬件保护关断如何分工？</p></li><li><p>我看到 <code>boost_types.h</code> 把配置、采样和运行状态分开。公司工程里参数表、实时变量和故障状态通常怎么组织？</p></li></ul><p>**下一步：**先不要跳到 PFC 或逆变器。把这个 C 骨架里的每个结构体字段标注清楚，再回看 Python 仿真图，确认“波形现象”和“软件状态”能互相对应。</p><p>关联：<a href="./0005-boost-firmware-skeleton.html">上一节：Boost 控制中断软件骨架</a>；源稿：<code>concepts/embedded/boost-c-firmware-skeleton.md</code>。</p><pre><code>上一节：教程 0005：Boost 控制中断服务程序（control interrupt service routine / control ISR）软件骨架
下一节：教程 0007：Boost 故障锁存与复位状态机
</code></pre>`,40)])])}const m=o(a,[["render",l]]);export{u as __pageData,m as default};
